class NestedIterator {
    stack<vector<NestedInteger>::const_iterator> stBegin, stEnd;
public:
    NestedIterator(vector<NestedInteger> &nestedList) {
        stBegin.push(nestedList.begin());
        stEnd.push(nestedList.end());
    }

    int next() {
        hasNext();
        return (stBegin.top()++)->getInteger();
    }

    bool hasNext() {
        while (!stBegin.empty()) {
            if (stBegin.top() == stEnd.top()) {
                stBegin.pop();
                stEnd.pop();
            } else {
                auto &cur = *stBegin.top();
                if (cur.isInteger()) return true;
                stBegin.top()++;
                const auto &lst = cur.getList();
                stBegin.push(lst.begin());
                stEnd.push(lst.end());
            }
        }
        return false;
    }
};
```
efficiency: HIGH
time complexity: O(1) amortized per next/hasNext call
space complexity: O(D) where D is the maximum nesting depth
energy implications: LOW
explanation: Uses an explicit stack to perform iterative DFS, avoiding recursion. Each element is pushed/popped at most once, giving amortized O(1) per operation. Stack size equals current nesting depth.

